import re

with open('input.tex') as f:
    text = f.read()

words_in_text = set(re.findall(r'[a-zA-Z]+', text))

with open('synonyms.txt') as f:
    synonym_map = {}
    for line in f:
        parts = line.strip().split(', ')
        if parts:
            base = parts[0].lower()
            synonyms = [s.lower() for s in parts]
            synonym_map[base] = synonyms

# Find words that can be replaced with shorter synonyms
for word in sorted(words_in_text):
    w_lower = word.lower()
    if w_lower in synonym_map:
        syns = synonym_map[w_lower]
        shorter = [s for s in syns if len(s) < len(word)]
        if shorter:
            best = min(shorter, key=len)
            print(f"{word} ({len(word)}) -> {best} ({len(best)}) saves {len(word)-len(best)}")
EOF"}
